import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Login.css';

const Login = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const validateForm = () => {
        if (!email || !email.includes('@')) {
            setError('Please enter a valid email address');
            return false;
        }
        if (!password || password.length < 6) {
            setError('Password must be at least 6 characters long');
            return false;
        }
        if (!isLogin && password !== confirmPassword) {
            setError('Passwords do not match');
            return false;
        }
        return true;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!validateForm()) return;

        setLoading(true);
        try {
            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 1500));

            // Store in localStorage
            localStorage.setItem('user', JSON.stringify({
                email,
                name: email.split('@')[0]
            }));

            // Redirect to dashboard
            navigate('/dashboard');
        } catch (err) {
            setError('Authentication failed. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleGoogleAuth = () => {
        window.location.href = '/api/auth/google';
    };

    const handleForgotPassword = () => {
        if (!email) {
            setError('Please enter your email address');
            return;
        }
        alert(`Password reset link sent to ${email}`);
    };

    return (
        <div className="auth-container">
            {/* Left Section - Branding */}
            <div className="brand-section">
                <div className="brand-content">
                    <h1 className="brand-title">
                        <span className="title-line title-part-1">TICKET</span>
                        <span className="title-line title-part-2">MANAGEMENT</span>
                        <span className="title-line title-part-3">SYSTEM</span>
                    </h1>
                    <p className="brand-subtitle">
                        Streamline your workflow with our powerful ticket management solution
                    </p>
                    <div className="brand-features">
                        <div className="feature">
                            <span className="feature-icon">✅</span>
                            <span>Secure Authentication</span>
                        </div>
                        <div className="feature">
                            <span className="feature-icon">⚡</span>
                            <span>Real-time Updates</span>
                        </div>
                        <div className="feature">
                            <span className="feature-icon">🔒</span>
                            <span>Enterprise Grade Security</span>
                        </div>
                    </div>
                </div>
                <div className="brand-footer">
                    <p>© 2024 TMS Pro. All rights reserved.</p>
                </div>
            </div>

            {/* Right Section - Authentication Form */}
            <div className="auth-section">
                <div className="auth-card">
                    <div className="auth-header">
                        <h2 className="auth-title">
                            {isLogin ? 'WELCOME BACK' : 'CREATE ACCOUNT'}
                        </h2>
                        <p className="auth-subtitle">
                            {isLogin ? 'Please enter your details' : 'Start your journey with us'}
                        </p>
                    </div>

                    {error && (
                        <div className="error-alert">
                            <span className="error-icon">⚠️</span>
                            <span>{error}</span>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="auth-form">
                        <div className="form-group">
                            <label htmlFor="email" className="form-label">Email</label>
                            <input
                                type="email"
                                id="email"
                                className="form-input"
                                placeholder="Enter your email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label htmlFor="password" className="form-label">Password</label>
                            <input
                                type="password"
                                id="password"
                                className="form-input"
                                placeholder="Enter your password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />
                        </div>

                        {!isLogin && (
                            <div className="form-group">
                                <label htmlFor="confirmPassword" className="form-label">Confirm Password</label>
                                <input
                                    type="password"
                                    id="confirmPassword"
                                    className="form-input"
                                    placeholder="Confirm your password"
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    required
                                />
                            </div>
                        )}

                        {isLogin && (
                            <div className="form-options">
                                <label className="checkbox-label">
                                    <input
                                        type="checkbox"
                                        checked={rememberMe}
                                        onChange={(e) => setRememberMe(e.target.checked)}
                                    />
                                    <span className="checkbox-custom"></span>
                                    <span>Remember me</span>
                                </label>
                                <button
                                    type="button"
                                    className="forgot-password"
                                    onClick={handleForgotPassword}
                                >
                                    Forgot password?
                                </button>
                            </div>
                        )}

                        <button
                            type="submit"
                            className="submit-btn"
                            disabled={loading}
                        >
                            {loading ? (
                                <span className="loading-spinner"></span>
                            ) : isLogin ? (
                                'Sign in'
                            ) : (
                                'Sign up'
                            )}
                        </button>

                        <div className="divider">
                            <span className="divider-line"></span>
                            <span className="divider-text">OR CONTINUE WITH</span>
                            <span className="divider-line"></span>
                        </div>

                        <button
                            type="button"
                            className="google-btn"
                            onClick={handleGoogleAuth}
                        >
                            <img 
                                src="https://www.google.com/favicon.ico" 
                                alt="Google" 
                                className="google-icon"
                            />
                            Sign in with Google
                        </button>

                        <div className="auth-switch">
                            <span>
                                {isLogin ? "Don't have an account?" : "Already have an account?"}
                            </span>
                            <button
                                type="button"
                                className="switch-btn"
                                onClick={() => {
                                    setIsLogin(!isLogin);
                                    setError('');
                                    setConfirmPassword('');
                                }}
                            >
                                {isLogin ? 'Sign up for free!' : 'Sign in'}
                            </button>
                        </div>
                    </form>

                    <div className="progress-container">
                        <div className="progress-bar">
                            <div className="progress-fill"></div>
                        </div>
                        <span className="progress-text">73%</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Login;
